import{_ as d,b as o,o as a,i as r,j as s,g as c,aB as i}from"./chunks/framework._ZAOES46.js";const f=JSON.parse('{"title":"FaSteps 步骤条","description":"","frontmatter":{},"headers":[],"relativePath":"components/pro/FaSteps.md","filePath":"components/pro/FaSteps.md"}'),l={name:"components/pro/FaSteps.md"};function n(h,t,p,b,m,u){const e=o("Badge");return a(),r("div",null,[t[0]||(t[0]=s("div",{style:{display:"none"},hidden:"true","aria-hidden":"true","data-nosnippet":""},"Are you an LLM? You can read better optimized documentation at /components/pro/FaSteps.md for this page in Markdown format",-1)),c(e,{type:"pro",text:"专业版"}),t[1]||(t[1]=i('<h1 id="fasteps-步骤条" tabindex="-1">FaSteps 步骤条 <a class="header-anchor" href="#fasteps-步骤条" aria-label="Permalink to “FaSteps 步骤条”">​</a></h1><p>步骤条组件，用于展示流程进度、当前步骤状态和每个步骤的扩展内容。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>分步表单</li><li>订单流程跟踪</li><li>审批流程展示</li><li>向导式配置流程</li><li>任务执行进度展示</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>steps</code></td><td><code>StepsItem[]</code></td><td>-</td><td>步骤列表</td></tr><tr><td><code>status</code></td><td><code>&#39;error&#39; | &#39;process&#39; | &#39;wait&#39; | &#39;finish&#39;</code></td><td><code>&#39;process&#39;</code></td><td>当前步骤状态</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>自定义 CSS 类</td></tr></tbody></table><h3 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to “Model”">​</a></h3><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>modelValue</code></td><td><code>number</code></td><td><code>0</code></td><td>当前步骤下标，从 <code>0</code> 开始</td></tr></tbody></table><h3 id="stepsitem" tabindex="-1">StepsItem <a class="header-anchor" href="#stepsitem" aria-label="Permalink to “StepsItem”">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>string</code></td><td>步骤唯一标识，也是具名插槽名称</td></tr><tr><td><code>title</code></td><td><code>string</code></td><td>步骤标题</td></tr><tr><td><code>description</code></td><td><code>string</code></td><td>步骤描述</td></tr></tbody></table><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><p>每个步骤都可以通过 <code>steps.id</code> 对应的具名插槽扩展内容。</p><table tabindex="0"><thead><tr><th>名称</th><th>说明</th><th>作用域参数</th></tr></thead><tbody><tr><td><code>[steps.id]</code></td><td>指定步骤的扩展内容</td><td><code>step: StepsItem</code> - 当前步骤数据<br><code>index: number</code> - 当前步骤下标<br><code>status: StepsStatus</code> - 当前步骤最终状态<br><code>active: boolean</code> - 是否为当前步骤<br><code>finished: boolean</code> - 是否已完成</td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><strong>步骤下标</strong>：<code>modelValue</code> 从 <code>0</code> 开始，和 <code>steps</code> 数组下标保持一致</li><li><strong>状态含义</strong>： <ul><li><code>process</code>：当前步骤进行中，显示步骤序号</li><li><code>wait</code>：当前步骤等待中，显示加载图标和呼吸动效</li><li><code>finish</code>：当前步骤完成，显示完成图标</li><li><code>error</code>：当前步骤异常，显示错误图标</li></ul></li><li><strong>完成态判断</strong>：当前步骤之前的步骤会自动视为已完成；当当前步骤 <code>status</code> 为 <code>finish</code> 时，当前步骤也视为已完成</li><li><strong>具名插槽</strong>：插槽名称来自 <code>steps.id</code>，请确保每个步骤的 <code>id</code> 唯一且适合作为 Vue slot name</li><li><strong>样式来源</strong>：组件基于 shadcn-vue Stepper 实现，并保留少量状态色和图标映射</li></ol>',15))])}const _=d(l,[["render",n]]);export{f as __pageData,_ as default};
